# app/controllers/admin/users_controller.rb
class Admin::UsersController < ApplicationController
  before_action :require_admin
  before_action :set_user, only: [:edit, :update, :destroy]

  def index
    @users = User.all.order(created_at: :desc)
  end

  def new
    @user = User.new
  end

  def create
    @user = User.new(params[:user])
    if @user.save
      redirect_to admin_users_path, notice: 'User created successfully.'
    else
      render :new
    end
  end

  def edit
  end

  def update
    if @user.update_attributes(params[:user])
      redirect_to admin_users_path, notice: 'User updated successfully.'
    else
      render :edit
    end
  end

  def destroy
    @user.destroy
    redirect_to admin_users_path, notice: 'User deleted successfully.'
  end

  private

  def set_user
    @user = User.find(params[:id])
  end

  def require_admin
    redirect_to root_path, alert: 'Access denied.' unless current_user&.admin?
  end
end

# config/routes.rb
Rails.application.routes.draw do
  namespace :admin do
    resources :users
  end
end

# app/views/admin/users/index.html.erb
<h1>Manage Users</h1>

<%= link_to 'New User', new_admin_user_path, class: 'btn btn-primary' %>

<table class="table">
  <thead>
    <tr>
      <th>ID</th>
      <th>Email</th>
      <th>Role</th>
      <th>Admin</th>
      <th>Credits</th>
      <th>Actions</th>
    </tr>
  </thead>
  <tbody>
    <% @users.each do |user| %>
      <tr>
        <td><%= user.id %></td>
        <td><%= user.email %></td>
        <td><%= user.role %></td>
        <td><%= user.admin? ? 'Yes' : 'No' %></td>
        <td><%= user.account_credits %></td>
        <td>
          <%= link_to 'Edit', edit_admin_user_path(user), class: 'btn btn-sm btn-warning' %>
          <%= link_to 'Delete', admin_user_path(user), method: :delete, data: { confirm: 'Are you sure?' }, class: 'btn btn-sm btn-danger' %>
        </td>
      </tr>
    <% end %>
  </tbody>
</table>

# app/views/admin/users/edit.html.erb
<h1>Edit User</h1>

<%= form_for @user, url: admin_user_path(@user) do |f| %>
  <% if @user.errors.any? %>
    <div class="alert alert-danger">
      <ul>
        <% @user.errors.full_messages.each do |msg| %>
          <li><%= msg %></li>
        <% end %>
      </ul>
    </div>
  <% end %>

  <div class="form-group">
    <%= f.label :email %>
    <%= f.email_field :email, class: 'form-control' %>
  </div>

  <div class="form-group">
    <%= f.label :password %>
    <%= f.password_field :password, class: 'form-control' %>
  </div>

  <div class="form-group">
    <%= f.label :password_confirmation %>
    <%= f.password_field :password_confirmation, class: 'form-control' %>
  </div>

  <div class="form-group">
    <%= f.label :role %>
    <%= f.select :role, ['user', 'moderator', 'admin'], {}, class: 'form-control' %>
  </div>

  <div class="form-group">
    <%= f.label :admin %>
    <%= f.check_box :admin %>
  </div>

  <div class="form-group">
    <%= f.label :account_credits %>
    <%= f.number_field :account_credits, class: 'form-control' %>
  </div>

  <%= f.submit 'Update User', class: 'btn btn-primary' %>
  <%= link_to 'Cancel', admin_users_path, class: 'btn btn-secondary' %>
<% end %>

